import React, { useEffect, useState, useRef } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import io from 'socket.io-client';

// Fix leaflet default icon issue in React
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: require('leaflet/dist/images/marker-icon-2x.png'),
  iconUrl: require('leaflet/dist/images/marker-icon.png'),
  shadowUrl: require('leaflet/dist/images/marker-shadow.png'),
});

const SOCKET_URL = 'http://localhost:3000';

const MapView = () => {
  const [vehicles, setVehicles] = useState({});
  const [isConnected, setIsConnected] = useState(false);
  const socketRef = useRef(null);

  useEffect(() => {
    socketRef.current = io(SOCKET_URL);

    socketRef.current.on('connect', () => {
      setIsConnected(true);
      console.log('Connected to telemetry stream');
    });

    socketRef.current.on('telemetry_update', (data) => {
      // data: { imei, vehicleRegistration, driverName, location: { lat, lng }, speed, ignition, timestamp }
      setVehicles((prev) => ({
        ...prev,
        [data.imei]: data
      }));
    });

    socketRef.current.on('disconnect', () => {
      setIsConnected(false);
    });

    return () => {
      if (socketRef.current) {
        socketRef.current.disconnect();
      }
    };
  }, []);

  const defaultCenter = [19.0760, 72.8777]; // Mumbai center
  const vehicleList = Object.values(vehicles);

  return (
    <div className="w-full h-full relative">
      {!isConnected && (
        <div className="absolute inset-0 z-[1000] bg-white bg-opacity-70 flex flex-col items-center justify-center">
          <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
          <p className="text-sm font-medium text-slate-600">Initializing telemetry pipeline...</p>
        </div>
      )}
      
      <MapContainer center={defaultCenter} zoom={11} style={{ height: '100%', width: '100%' }}>
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          url="https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png"
        />
        
        {vehicleList.map((vehicle) => (
          <Marker 
            key={vehicle.imei} 
            position={[vehicle.location.lat, vehicle.location.lng]}
          >
            <Popup className="rounded-lg shadow-lg">
              <div className="p-1 min-w-[200px]">
                <h4 className="font-bold text-slate-800 text-lg mb-1">{vehicle.vehicleRegistration}</h4>
                <p className="text-sm text-slate-600 mb-2">Driver: <span className="font-medium text-slate-800">{vehicle.driverName}</span></p>
                
                <div className="bg-slate-50 p-2 rounded-md border border-slate-100 grid grid-cols-2 gap-2">
                  <div>
                    <span className="text-xs text-slate-500 block uppercase">Speed</span>
                    <span className="font-bold text-indigo-600">{vehicle.speed} km/h</span>
                  </div>
                  <div>
                    <span className="text-xs text-slate-500 block uppercase">Ignition</span>
                    <span className={`font-bold ${vehicle.ignition ? 'text-emerald-500' : 'text-slate-400'}`}>
                      {vehicle.ignition ? 'ON' : 'OFF'}
                    </span>
                  </div>
                </div>
                
                <div className="mt-2 text-right">
                  <span className="text-[10px] text-slate-400">Last updated: {new Date(vehicle.timestamp).toLocaleTimeString()}</span>
                </div>
              </div>
            </Popup>
          </Marker>
        ))}
      </MapContainer>
    </div>
  );
};

export default MapView;
